$base64 = ""
$bytes = [Convert]::FromBase64String($base64)
$navbarHtml = [System.Text.Encoding]::UTF8.GetString($bytes)

$files = Get-ChildItem -Filter *.html

foreach ($file in $files) {
    if ($file.Name -eq "management-viewer.html") { continue }
    $content = [System.IO.File]::ReadAllText($file.FullName, [System.Text.Encoding]::UTF8)
    if ($content -match '(?s)<nav id="navbar".*?</nav>') {
        $oldNav = $Matches[0]
        $content = $content.Replace($oldNav, $navbarHtml)
        [System.IO.File]::WriteAllText($file.FullName, $content, [System.Text.Encoding]::UTF8)
        Write-Output "Fixed $($file.Name)"
    }
}

